var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우와~ 역시 대단하세요!","JPN":"わあ～さすがですね！","ENG":"Wow, you were amazing!","TWN":"哇～真是太厲害了！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"과연 경찰청이 단숨에 경정 자리에 꽂아둘 만한 인재다워요!","JPN":"さすが警察庁が一発で警視に任命する人材なだけありますね！","ENG":"No wonder the higher ups wanted to make you a major!","TWN":"真不愧是被警察廳一口氣提拔為警正的人才！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥! 입에 발린 말은 됐어.","JPN":"ふん！　お世辞はいらないわ。","ENG":"Hmpf! Buttering me up won't do you any good.","TWN":"哼！不需要妳拍馬屁。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그보다 당신들은 생각보다 더 엉망이네.","JPN":"それより、あなたたち思ったよりめちゃくちゃね。","ENG":"By the way, you lot are much worse than I thought.","TWN":"話說回來，你們這些傢伙，比我預想得還要糟糕呢。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런 변변찮은 악당들을 대상으로도 고전하다니, 고작 그런 실력으로 지금까지 범죄와 맞서왔다는 거야?","JPN":"こんな雑魚相手に苦戦するなんて、今までその程度の実力で犯罪に立ち向かってきたの？","ENG":"You don't even seem capable of dealing with small-time hoodlums like these. How on earth have you been fighting crimes?","TWN":"對付這些小小歹徒竟然也會陷入苦戰，你們一直以來都是用這種實力打擊犯罪的嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"역시 무능력자들다워. 이 도시가 멸망하지 않은 게 기적이네.","JPN":"さすが無能力者ね。この都市が滅びなかったのが奇跡だわ。","ENG":"Really, you incompetents never cease to disappoint me. It's a miracle that this city hasn't been completely destroyed yet.","TWN":"真不愧是無能力者，這座城市還沒有被歹徒佔領簡直是奇跡。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 아까부터 무능력자라고 하시는데...... 혹시 저 말인가요?","JPN":"あの……さっきから無能力者って言ってますけど……\\nそれって私のことですか？","ENG":"Um... You keep saying incompetent. Are you referring to me, Major?","TWN":"呃……妳剛才開始就在說無能力者……該不會是在說我吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그래. 당신은 카운터가 아니잖아?","JPN":"そう。あなたはカウンターじゃないでしょう？","ENG":"I am. You're no Counter.","TWN":"是啊。妳不是制裁者啊？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"전혀 도움이 안되니까 앞으로는 괜히 현장에 참견할 생각 말고 서류 작업이나 해 두라고.","JPN":"全く役に立たないから、現場に首を突っ込まないで\\n書類仕事でもしなさい。","ENG":"You're useless out in the field. So why don't you just stick with a desk job?","TWN":"妳完全幫不上忙，所以也別想要管現場的事了，去做個文書作業吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하...... 그게 경정님 지시라면 어쩔 수 없죠.","JPN":"はは……警視様のご指示なら仕方ありませんね。","ENG":"Hah hah... Well, your wish is my command, Major.","TWN":"哈哈…… 既然是警正大人的命令，那就沒辦法了呢。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 현장 확인은 경정님이 진행하실 건가요?","JPN":"では、現場確認は警視様がおやりになるんですか？","ENG":"Does that mean you'll go investigate the crime scene yourself?","TWN":"那現場確認就由警正大人親自去做嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......현장 확인?","JPN":"……現場確認？","ENG":"What do you mean?","TWN":"……現場確認？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그게 뭐야? 감히 경찰 건물에 쳐들어 온 범죄자를 때려잡는데 그런 게 왜 필요해?!","JPN":"何それ？　警察の建物に侵入した犯罪者を捕まえるのに、\\nなぜそんなことが必要なの？","ENG":"Why? Who needs to investigate anything when we're busy enough beating up criminals who had the gall to raid a police building?!","TWN":"那是什麼？抓住膽敢闖入警察廳的犯罪者，為什麼需要那種東西？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 음...... 왜냐고 물으시면...... 절차니까요?","JPN":"え……うーん……なぜって聞かれますと……\\nそれが決まりだから？","ENG":"Err... Mm... Well... Because it's protocol?","TWN":"呃……嗯……妳問我為什麼……因為這是流程吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹시...... 경찰 교육은 따로 안 받으셨나요?","JPN":"ひょっとして……警察の基本業務教育は受けてないんですか？","ENG":"Hang on... Have you received any formal police training?","TWN":"妳該不會……沒有受過警察教育吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그","JPN":"そ、そんな……","ENG":"W-well...","TWN":"那、那……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"런 하찮은 일은 경위가 알아서 해! 난 범죄자들을 소탕하는 것만으로도 바쁘니까!","JPN":"そんなくだらないことは警部補がやればいいじゃない！\\n私は犯罪者を掃討するだけで忙しいから！","ENG":"I'll leave those petty details to you! I'm busy enough busting criminal skulls!","TWN":"那種小事就由警衛妳自行處理吧！我光是要掃蕩犯罪者，就已經忙得不可開交了！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 알겠습니다. 저야 항상 하던 일인데요 뭐.","JPN":"はは、わかりました。いつも私がやっていることですからね。","ENG":"Hah hah, yes, ma'am. This is a 365 days a year thing for me.","TWN":"哈哈，我明白了。反正是我一直在做的事情嘛。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"우, 우리는 묵비권을 행사하겠다!","JPN":"お、俺たちは黙秘権を行使するぞ！","ENG":"W-we're going to take the fifth!","TWN":"我、我們要行使沉默權！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"포기해라! 그 어떤 고문으로도 우리의 신념을 꺾을 수는 없을 것이다!","JPN":"諦めろ！　どんな拷問でも俺たちの信念を曲げることはできない！","ENG":"You won't get anything from us! Torture us all you want, but you'll never be able to kill our faith!","TWN":"放棄吧！無論是怎麼樣的拷問，都沒法摧折我們的信念！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"哼嗯……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐 딱히 자백 같은 거 안 해도 빵봉투를 뒤집어 쓴 테러리스트라면 어차피 하나뿐이죠.","JPN":"別に自白しなくても、紙袋を被ったテロリストなら一か所しかありません。","ENG":"We won't even need their confession. There's only one group of terrorists who wear paper bags.","TWN":"不招也沒關係，會在頭上套麵包袋的恐怖分子就只有他們了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"마젤란 예언회 놈들이네요.","JPN":"マジェラン預言会です。","ENG":"The Magellan's Prediction Society.","TWN":"他們應該是麥哲倫預言會的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"마젤란 예언회? 뭐야, 그 한물간 사이비종교 같은 이름은?","JPN":"マジェラン預言会？　何その怪しい宗教みたいな名前は？","ENG":"Magellan's Prediction Society? What a lame name. Are they some kind of a cult?","TWN":"麥哲倫預言會？什麼啊，這種像是過時偽邪教一樣的名字？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오, 경정님 추리력이 좋으신데요? 정확히 맞히셨어요.","JPN":"警視様、素晴らしい推理力ですね！　おっしゃるとおりです。","ENG":"Wow, Major. Good hunch. They are a cult.","TWN":"啊，警正大人。您的推理能力很不錯啊？完全正確。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"거기다가 최근에 엘릭서라는 불법 카운터 드러그를 제조 판매하는 조직인데 말이죠......","JPN":"最近エリクサーという違法カウンタードラッグを作って販売している組織なんですが……","ENG":"They're also a crime syndicate that has been producing and selling an illegal Counter drug called Elixir.","TWN":"而且他們這個組織最近還在製造，並販賣一種叫做聖水的非法制裁者毒品呢……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런 사이비들이 대낮에 정부기관을 공격했다고?","JPN":"そんな怪しい団体が真昼から政府機関を攻撃したってこと？","ENG":"You're saying a bunch of cult followers attacked government institution in broad daylight?","TWN":"這種邪教徒在大白天攻擊政府機關？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......그러게요.","JPN":"……そうですね。","ENG":"I know, right?","TWN":"……就是啊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"원래 대범하긴 했어도 이 정도로 무모하진 않았던 것 같은데.","JPN":"もともと大胆ではありましたけど、ここまで無謀ではなかった気がしますが。","ENG":"They're known to be bold in their crimes, but have never been this reckless.","TWN":"雖然他們本來就很大膽，但也沒有這麼魯莽。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"도대체 뭐가 목적이었던 걸까요?","JPN":"いったい何が目的だったんでしょうか？","ENG":"What purpose would this serve?","TWN":"究竟有什麼目的呢？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"여기에 뭔가...... 찾는 거라도 있었던 걸까요?","JPN":"ここに何か……探しているものでもあったんでしょうか？","ENG":"Is there something they're looking for in the premises?","TWN":"是要來這裡……找什麼東西嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};